 1→import type { ReactNode } from 'react';
 2→import type { TagColor } from './constants/tag_colors';
 3→
 4→export interface ListItemData {
 5→  id: string;
 6→  title: string;
 7→  subtitle?: string;
 8→  icon?: ReactNode;
 9→  accessories?: ListItemAccessoryData[];
10→  detail?: ListItemDetailData;
11→}
12→
13→export interface ListItemAccessoryData {
14→  text?: string;
15→  icon?: ReactNode;
16→  tag?: {
17→    text: string;
18→    color?: TagColor;
19→  };
20→}
21→
22→export interface ListItemDetailData {
23→  markdown: string;
24→  metadata?: ListItemMetadataEntry[];
25→}
26→
27→export type ListItemMetadataEntry =
28→  | {
29→      type: 'label';
30→      title: string;
31→      text?: string;
32→    }
33→  | {
34→      type: 'link';
35→      title: string;
36→      text: string;
37→      target: string;
38→    }
39→  | {
40→      type: 'tag-list';
41→      title: string;
42→      tags: {
43→        text: string;
44→        color?: TagColor;
45→      }[];
46→    }
47→  | { type: 'separator' };
48→
49→export interface SectionData {
50→  title: string;
51→  items: ListItemData[];
52→}
53→
54→export interface GridItemData {
55→  id: string;
56→  title: string;
57→  subtitle?: string;
58→  icon?: ReactNode;
59→}
