  1→import { useCallback, useEffect, useMemo, useState } from 'react';
  2→import { ActionPanel } from './components/action_panel/action_panel';
  3→import { CommandPalette } from './components/command_palette/command_palette';
  4→import { Detail } from './components/detail/detail';
  5→import { DetailMetadata } from './components/detail/detail_metadata';
  6→import { EmptyState } from './components/empty_state/empty_state';
  7→import {
  8→  Form,
  9→  FormCheckbox,
 10→  FormDatePicker,
 11→  FormDropdown,
 12→  FormTextArea,
 13→  FormTextField,
 14→} from './components/form';
 15→import { Grid, GridItem } from './components/grid';
 16→import { Kbd } from './components/kbd/kbd';
 17→import { List, ListItem, ListSection } from './components/list';
 18→import type { BreadcrumbItem } from './components/search_bar/search_bar';
 19→import { SearchBar } from './components/search_bar/search_bar';
 20→import { ToastContainer } from './components/toast/toast_container';
 21→import { MOCK_COLORS, MOCK_SECTIONS } from './data/mock_data';
 22→import { useToast } from './hooks/use_toast';
 23→import type {
 24→  ColorItemData,
 25→  ListItemData,
 26→  ListItemMetadataEntry,
 27→  SectionData,
 28→} from './types';
 29→
 30→function filterSections(sections: SectionData[], query: string): SectionData[] {
 31→  if (!query) return sections;
 32→  const lower = query.toLowerCase();
 33→  return sections
 34→    .map(section => ({
 35→      ...section,
 36→      items: section.items.filter(
 37→        item =>
 38→          item.title.toLowerCase().includes(lower) ||
 39→          item.subtitle?.toLowerCase().includes(lower),
 40→      ),
 41→    }))
 42→    .filter(section => section.items.length > 0);
 43→}
 44→
 45→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 46→  if (!query) return colors;
 47→  const lower = query.toLowerCase();
 48→  return colors.filter(
 49→    c =>
 50→      c.title.toLowerCase().includes(lower) ||
 51→      c.subtitle?.toLowerCase().includes(lower),
 52→  );
 53→}
 54→
 55→function flattenItems(sections: SectionData[]): ListItemData[] {
 56→  return sections.flatMap(s => s.items);
 57→}
 58→
 59→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 60→  switch (entry.type) {
 61→    case 'label':
 62→      return (
 63→        <DetailMetadata.Label
 64→          key={index}
 65→          title={entry.title}
 66→          text={entry.text}
 67→        />
 68→      );
 69→    case 'link':
 70→      return (
 71→        <DetailMetadata.Link
 72→          key={index}
 73→          title={entry.title}
 74→          text={entry.text}
 75→          target={entry.target}
 76→        />
 77→      );
 78→    case 'tag-list':
 79→      return (
 80→        <DetailMetadata.TagList key={index} title={entry.title}>
 81→          {entry.tags.map(tag => (
 82→            <DetailMetadata.Tag
 83→              key={tag.text}
 84→              text={tag.text}
 85→              color={tag.color}
 86→            />
 87→          ))}
 88→        </DetailMetadata.TagList>
 89→      );
 90→    case 'separator':
 91→      return <DetailMetadata.Separator key={index} />;
 92→  }
 93→}
 94→
 95→function ColorSwatch({ color }: { color: string }) {
 96→  return (
 97→    <div
 98→      className="grid-item__color-swatch"
 99→      style={{ backgroundColor: color }}
100→    />
101→  );
102→}
103→
104→function SearchIcon() {
105→  return (
106→    <svg
107→      width="48"
108→      height="48"
109→      viewBox="0 0 48 48"
110→      fill="none"
111→      xmlns="http://www.w3.org/2000/svg"
112→    >
113→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
114→      <line
115→        x1="30"
116→        y1="30"
117→        x2="42"
118→        y2="42"
119→        stroke="currentColor"
120→        strokeWidth="3"
121→        strokeLinecap="round"
122→      />
123→    </svg>
124→  );
125→}
126→
127→type ViewMode = 'list' | 'grid' | 'form';
128→
129→interface SnippetFormState {
130→  name: string;
131→  keyword: string;
132→  snippet: string;
133→  category: string;
134→  isShared: boolean;
135→  expiresAt: string;
136→}
137→
138→const INITIAL_SNIPPET_FORM: SnippetFormState = {
139→  name: '',
140→  keyword: '',
141→  snippet: '',
142→  category: 'general',
143→  isShared: false,
144→  expiresAt: '',
145→};
146→
147→const SNIPPET_CATEGORIES = [
148→  {
149→    label: 'General',
150→    value: 'general',
151→  },
152→  {
153→    label: 'Code',
154→    value: 'code',
155→  },
156→  {
157→    label: 'Email',
158→    value: 'email',
159→  },
160→  {
161→    label: 'Template',
162→    value: 'template',
163→  },
164→];
165→
166→export function App() {
167→  const [query, setQuery] = useState('');
168→  const [selectedIndex, setSelectedIndex] = useState(0);
169→  const [actionsOpen, setActionsOpen] = useState(false);
170→  const [drilledItem, setDrilledItem] = useState<ListItemData | null>(null);
171→  const [viewMode, setViewMode] = useState<ViewMode>('list');
172→  const [snippetForm, setSnippetForm] =
173→    useState<SnippetFormState>(INITIAL_SNIPPET_FORM);
174→  const [formErrors, setFormErrors] = useState<
175→    Partial<Record<keyof SnippetFormState, string>>
176→  >({});
177→  const { toasts, show: showToast, hide: hideToast } = useToast();
178→
179→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
180→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
181→  const filteredColors = useMemo(
182→    () => filterColors(MOCK_COLORS, query),
183→    [query],
184→  );
185→  const selectedItem =
186→    viewMode === 'list' ? (drilledItem ?? allItems[selectedIndex]) : undefined;
187→
188→  const handleQueryChange = useCallback((value: string) => {
189→    setQuery(value);
190→    setSelectedIndex(0);
191→    setActionsOpen(false);
192→  }, []);
193→
194→  const handleActiveIndexChange = useCallback((index: number) => {
195→    setSelectedIndex(index);
196→    setActionsOpen(false);
197→  }, []);
198→
199→  const handleDrillIn = useCallback(() => {
200→    const item = allItems[selectedIndex];
201→    if (item) {
202→      if (item.id === 'color-picker') {
203→        setViewMode('grid');
204→        setQuery('');
205→        setSelectedIndex(0);
206→        setActionsOpen(false);
207→        showToast({
208→          style: 'success',
209→          title: 'Opened Color Picker',
210→        });
211→      } else {
212→        setDrilledItem(item);
213→        setQuery('');
214→        setActionsOpen(false);
215→        showToast({
216→          style: 'success',
217→          title: `Opened ${item.title}`,
218→        });
219→      }
220→    }
221→  }, [
222→    allItems,
223→    selectedIndex,
224→    showToast,
225→  ]);
226→
227→  const handleDrillBack = useCallback(() => {
228→    setDrilledItem(null);
229→    setViewMode('list');
230→    setQuery('');
231→    setSelectedIndex(0);
232→    setActionsOpen(false);
233→    setSnippetForm(INITIAL_SNIPPET_FORM);
234→    setFormErrors({});
235→  }, []);
236→
237→  const handleOpenCreateSnippet = useCallback(() => {
238→    setViewMode('form');
239→    setQuery('');
240→    setSelectedIndex(0);
241→    setActionsOpen(false);
242→    setSnippetForm(INITIAL_SNIPPET_FORM);
243→    setFormErrors({});
244→  }, []);
245→
246→  const handleSubmitSnippet = useCallback(() => {
247→    const errors: Partial<Record<keyof SnippetFormState, string>> = {};
248→    if (!snippetForm.name.trim()) {
249→      errors.name = 'Name is required';
250→    }
251→    if (!snippetForm.snippet.trim()) {
252→      errors.snippet = 'Snippet content is required';
253→    }
254→    setFormErrors(errors);
255→    if (Object.keys(errors).length > 0) {
256→      return;
257→    }
258→    showToast({
259→      style: 'success',
260→      title: 'Snippet Created',
261→      message: snippetForm.name,
262→    });
263→    handleDrillBack();
264→  }, [
265→    snippetForm,
266→    showToast,
267→    handleDrillBack,
268→  ]);
269→
270→  const handleGridAction = useCallback(
271→    (index: number) => {
272→      const color = filteredColors[index];
273→      if (color) {
274→        showToast({
275→          style: 'info',
276→          title: 'Copied color',
277→          message: color.color,
278→        });
279→      }
280→    },
281→    [
282→      filteredColors,
283→      showToast,
284→    ],
285→  );
286→
287→  const breadcrumbs: BreadcrumbItem[] | undefined =
288→    viewMode === 'form'
289→      ? [
290→          {
291→            label: 'Raycast',
292→            onBack: handleDrillBack,
293→          },
294→          { label: 'Create Snippet' },
295→        ]
296→      : viewMode === 'grid'
297→        ? [
298→            {
299→              label: 'Raycast',
300→              onBack: handleDrillBack,
301→            },
302→            { label: 'Color Picker' },
303→          ]
304→        : drilledItem
305→          ? [
306→              {
307→                label: 'Raycast',
308→                onBack: handleDrillBack,
309→              },
310→              { label: drilledItem.title },
311→            ]
312→          : undefined;
313→
314→  const toggleActions = useCallback(() => {
315→    setActionsOpen(prev => !prev);
316→  }, []);
317→
318→  const closeActions = useCallback(() => {
319→    setActionsOpen(false);
320→  }, []);
321→
322→  useEffect(() => {
323→    function handleKeyDown(e: KeyboardEvent) {
324→      if (e.key === 'k' && e.metaKey && viewMode !== 'form') {
325→        e.preventDefault();
326→        setActionsOpen(prev => !prev);
327→        return;
328→      }
329→      if (e.key === 'Enter' && e.metaKey && viewMode === 'form') {
330→        e.preventDefault();
331→        handleSubmitSnippet();
332→        return;
333→      }
334→      if (e.key === 'n' && e.metaKey && viewMode !== 'form') {
335→        e.preventDefault();
336→        handleOpenCreateSnippet();
337→      }
338→    }
339→
340→    window.addEventListener('keydown', handleKeyDown);
341→    return () => window.removeEventListener('keydown', handleKeyDown);
342→  }, [
343→    viewMode,
344→    handleSubmitSnippet,
345→    handleOpenCreateSnippet,
346→  ]);
347→
348→  const detail = selectedItem?.detail;
349→
350→  const dropdownActions = useMemo(
351→    () => [
352→      {
353→        label: 'Open',
354→        shortcut: <Kbd keys={['↵']} />,
355→        onClick: () => {
356→          if (selectedItem) {
357→            showToast({
358→              style: 'success',
359→              title: `Opened ${selectedItem.title}`,
360→            });
361→          }
362→        },
363→      },
364→      {
365→        label: 'Copy Name',
366→        shortcut: (
367→          <Kbd
368→            keys={[
369→              '⌘',
370→              'C',
371→            ]}
372→          />
373→        ),
374→        onClick: () => {
375→          if (selectedItem) {
376→            showToast({
377→              style: 'info',
378→              title: 'Copied to clipboard',
379→              message: selectedItem.title,
380→            });
381→          }
382→        },
383→      },
384→      {
385→        label: 'Show Detail',
386→        shortcut: (
387→          <Kbd
388→            keys={[
389→              '⌘',
390→              'D',
391→            ]}
392→          />
393→        ),
394→        onClick: () => {
395→          showToast({
396→            style: 'info',
397→            title: 'Detail panel toggled',
398→          });
399→        },
400→      },
401→      {
402→        label: 'Create Snippet',
403→        shortcut: (
404→          <Kbd
405→            keys={[
406→              '⌘',
407→              'N',
408→            ]}
409→          />
410→        ),
411→        onClick: handleOpenCreateSnippet,
412→      },
413→      {
414→        label: 'Delete',
415→        shortcut: (
416→          <Kbd
417→            keys={[
418→              '⌘',
419→              '⌫',
420→            ]}
421→          />
422→        ),
423→        onClick: () => {
424→          showToast({
425→            style: 'error',
426→            title: 'Cannot delete',
427→            message: 'This item is read-only',
428→          });
429→        },
430→      },
431→    ],
432→    [
433→      selectedItem,
434→      showToast,
435→      handleOpenCreateSnippet,
436→    ],
437→  );
438→
439→  const activeDescendantId =
440→    viewMode === 'grid'
441→      ? filteredColors.length > 0
442→        ? `grid-item-${selectedIndex}`
443→        : undefined
444→      : allItems.length > 0
445→        ? `list-item-${selectedIndex}`
446→        : undefined;
447→
448→  return (
449→    <CommandPalette isLoading>
450→      <SearchBar
451→        value={query}
452→        onChange={handleQueryChange}
453→        activeDescendantId={activeDescendantId}
454→        breadcrumbs={breadcrumbs}
455→      />
456→      <div
457→        className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
458→      >
459→        <div className="command-palette__list-container">
460→          {viewMode === 'form' ? (
461→            <Form onSubmit={handleSubmitSnippet}>
462→              <FormTextField
463→                label="Name"
464→                value={snippetForm.name}
465→                onChange={v =>
466→                  setSnippetForm(prev => ({
467→                    ...prev,
468→                    name: v,
469→                  }))
470→                }
471→                placeholder="e.g. Email Signature"
472→                error={formErrors.name}
473→                autoFocus
474→              />
475→              <FormTextField
476→                label="Keyword"
477→                value={snippetForm.keyword}
478→                onChange={v =>
479→                  setSnippetForm(prev => ({
480→                    ...prev,
481→                    keyword: v,
482→                  }))
483→                }
484→                placeholder="e.g. !sig"
485→                description="Type this to expand the snippet"
486→              />
487→              <FormDropdown
488→                label="Category"
489→                value={snippetForm.category}
490→                onChange={v =>
491→                  setSnippetForm(prev => ({
492→                    ...prev,
493→                    category: v,
494→                  }))
495→                }
496→                options={SNIPPET_CATEGORIES}
497→                placeholder="Select a category"
498→              />
499→              <FormTextArea
500→                label="Snippet"
501→                value={snippetForm.snippet}
502→                onChange={v =>
503→                  setSnippetForm(prev => ({
504→                    ...prev,
505→                    snippet: v,
506→                  }))
507→                }
508→                placeholder="Enter your snippet content..."
509→                error={formErrors.snippet}
510→                rows={5}
511→              />
512→              <FormCheckbox
513→                label="Share with team"
514→                checked={snippetForm.isShared}
515→                onChange={v =>
516→                  setSnippetForm(prev => ({
517→                    ...prev,
518→                    isShared: v,
519→                  }))
520→                }
521→                description="Make this snippet available to your team members"
522→              />
523→              <FormDatePicker
524→                label="Expires"
525→                value={snippetForm.expiresAt}
526→                onChange={v =>
527→                  setSnippetForm(prev => ({
528→                    ...prev,
529→                    expiresAt: v,
530→                  }))
531→                }
532→                description="Optional expiration date"
533→              />
534→            </Form>
535→          ) : viewMode === 'grid' ? (
536→            filteredColors.length === 0 ? (
537→              <EmptyState
538→                icon={<SearchIcon />}
539→                title="No Colors"
540→                description="Try a different search term"
541→              />
542→            ) : (
543→              <Grid
544→                itemCount={filteredColors.length}
545→                columns={4}
546→                onActiveIndexChange={handleActiveIndexChange}
547→                onAction={handleGridAction}
548→              >
549→                {filteredColors.map((color, index) => (
550→                  <GridItem
551→                    key={color.id}
552→                    index={index}
553→                    icon={<ColorSwatch color={color.color} />}
554→                    title={color.title}
555→                    subtitle={color.subtitle}
556→                  />
557→                ))}
558→              </Grid>
559→            )
560→          ) : allItems.length === 0 ? (
561→            <EmptyState
562→              icon={<SearchIcon />}
563→              title="No Results"
564→              description="Try a different search term"
565→            />
566→          ) : (
567→            <List
568→              itemCount={allItems.length}
569→              onActiveIndexChange={handleActiveIndexChange}
570→              onAction={handleDrillIn}
571→            >
572→              {(() => {
573→                let globalIndex = 0;
574→                return filtered.map(section => (
575→                  <ListSection key={section.title} title={section.title}>
576→                    {section.items.map(item => {
577→                      const idx = globalIndex++;
578→                      return (
579→                        <ListItem
580→                          key={item.id}
581→                          index={idx}
582→                          title={item.title}
583→                          subtitle={item.subtitle}
584→                          icon={item.icon}
585→                          accessories={item.accessories}
586→                        />
587→                      );
588→                    })}
589→                  </ListSection>
590→                ));
591→              })()}
592→            </List>
593→          )}
594→        </div>
595→        {detail && (
596→          <Detail
597→            markdown={detail.markdown}
598→            metadata={
599→              detail.metadata ? (
600→                <DetailMetadata>
601→                  {detail.metadata.map(renderMetadataEntry)}
602→                </DetailMetadata>
603→              ) : undefined
604→            }
605→          />
606→        )}
607→      </div>
608→      <ActionPanel
609→        contextLabel={
610→          viewMode === 'form'
611→            ? 'Create Snippet'
612→            : viewMode === 'grid'
613→              ? 'Color Picker'
614→              : drilledItem
615→                ? drilledItem.title
616→                : 'Raycast'
617→        }
618→        actions={
619→          viewMode === 'form'
620→            ? [
621→                {
622→                  label: 'Submit',
623→                  shortcut: (
624→                    <Kbd
625→                      keys={[
626→                        '⌘',
627→                        '↵',
628→                      ]}
629→                    />
630→                  ),
631→                  onClick: handleSubmitSnippet,
632→                },
633→              ]
634→            : [
635→                {
636→                  label: 'Open',
637→                  shortcut: <Kbd keys={['↵']} />,
638→                },
639→                {
640→                  label: 'Actions',
641→                  shortcut: (
642→                    <Kbd
643→                      keys={[
644→                        '⌘',
645→                        'K',
646→                      ]}
647→                    />
648→                  ),
649→                  onClick: toggleActions,
650→                },
651→              ]
652→        }
653→        dropdownOpen={actionsOpen}
654→        dropdownActions={dropdownActions}
655→        onDropdownClose={closeActions}
656→      />
657→      <ToastContainer toasts={toasts} onDismiss={hideToast} />
658→    </CommandPalette>
659→  );
660→}
